function myReduce(array, init, f) {
  var acc = init;
  for (let i = 0; i < array.length; i++) {
    acc = f(acc, array[i]);
  }
  return acc;
}

console.log(myReduce([1, 2, 3, 4], 0, (acc, x) => acc + x));

